#!/usr/bin/env node
/**
 * bundle.js — Binga Geoportal Layer Bundler (Node.js version)
 * Run from the Geoportal folder:   node bundle.js
 */

const fs   = require('fs');
const path = require('path');

const LAYERS_DIR  = path.join(__dirname, 'assets', 'layers');
const OUTPUT_FILE = path.join(__dirname, 'js', 'layers-data.js');

const LAYER_KEYS = [
  'districtBoundary', 'wardBoundaries',  'villages',
  'roads',            'clinics',          'hospitals',
  'schools',          'touristSites',     'businessCentres',
  'serviceCentres',   'rivers',           'dams',
  'waterPoints',      'nationalParks',    'conservancies',
  'policeStations',   'policeBases',      'borderPosts',
  'airstrips',        'miningClaims',     'fishingCamps',
  'hotSprings',
];

console.log(`\nBinga Geoportal — bundling layers from:\n  ${LAYERS_DIR}\n`);

if (!fs.existsSync(LAYERS_DIR)) {
  console.error('ERROR: Layers folder not found:', LAYERS_DIR);
  process.exit(1);
}

const data = {};
const missing = [];

for (const key of LAYER_KEYS) {
  const file = path.join(LAYERS_DIR, `${key}.geojson`);
  if (fs.existsSync(file)) {
    data[key] = JSON.parse(fs.readFileSync(file, 'utf8'));
    const count = data[key].features?.length ?? 0;
    console.log(`  ✓  ${key.padEnd(22)} ${count} feature${count !== 1 ? 's' : ''}`);
  } else {
    missing.push(key);
    console.log(`  ✗  ${key.padEnd(22)} (not found — skipped)`);
  }
}

const js =
`/* ═══════════════════════════════════════════════════
   layers-data.js — Auto-generated by bundle.js
   Binga Geoportal

   DO NOT EDIT THIS FILE MANUALLY.
   Edit the .geojson files in assets/layers/ using QGIS,
   then re-run:  node bundle.js
   ═══════════════════════════════════════════════════ */

var sampleData = ${JSON.stringify(data, null, 2)};
`;

fs.mkdirSync(path.dirname(OUTPUT_FILE), { recursive: true });
fs.writeFileSync(OUTPUT_FILE, js, 'utf8');

const total = Object.values(data).reduce((s,v) => s + (v.features?.length ?? 0), 0);
const size  = Math.round(fs.statSync(OUTPUT_FILE).size / 1024);

console.log(`\n  Bundled ${Object.keys(data).length}/${LAYER_KEYS.length} layers`);
console.log(`  Total features : ${total}`);
console.log(`  Output         : ${OUTPUT_FILE}  (${size} KB)`);
if (missing.length) console.log(`  Missing files  : ${missing.join(', ')}`);
console.log('\n  Done! Reload index.html in your browser.\n');
